    if (!full) continue;
    nameMap[full] = full;
    const parts = full.trim().split(/\s+/);
    if (parts.length >= 2) {
      const abbrev = parts[0].charAt(0).toUpperCase() + '. ' + parts.slice(1).join(' ');
