function fmtTeam(t) {
  const f  = flag(t.team?.name || '');
  const xi = (t.startXI || [])
    .sort((a,b) => (posOrder[a.player?.pos]||5) - (posOrder[b.player?.pos]||5))
    .map(p => (nameMap[p.player?.name] || p.player?.name || ''))
    .filter(Boolean).join('  ·  ');
  return [`${f} ${t.team?.name} (${t.formation||'?'})  ·  DT: ${t.coach?.name||'?'}`, xi].join('\n');
