// Override: si el suscriptor tiene tz_offset guardado en DB (detector de país), usarlo SIEMPRE
function tzDeDB(row) {
  if (row && row.tz_offset !== null && row.tz_offset !== undefined && row.tz_offset !== '') {
    const o = parseInt(row.tz_offset);
    if (!isNaN(o)) return { offset: o, etiqueta: row.pais_db || 'tu país' };
  }
  return null;
}
const sub    = $('Loop Subs EVT').first().json;
const tipo   = sub.tipo;
const promo  = sub.sponsor_promo  || '';
const image  = sub.sponsor_image  || '';

// Per-subscriber timezone for {{HORA_PROXIMO}}
let msgWa = sub.msg_wa || '';
let msgTg = sub.msg_tg || '';
if (sub.next_match_utc_ts && msgWa.includes('{{HORA_PROXIMO}}')) {
  const p = String(sub.phone || '');
  let offset = -6, pais = 'El Salvador';
  if      (/^52/.test(p))          { offset = -6; pais = 'México'; }
  else if (/^503/.test(p))         { offset = -6; pais = 'El Salvador'; }
  else if (/^502/.test(p))         { offset = -6; pais = 'Guatemala'; }
  else if (/^504/.test(p))         { offset = -6; pais = 'Honduras'; }
  else if (/^505/.test(p))         { offset = -6; pais = 'Nicaragua'; }
  else if (/^51/.test(p))          { offset = -5; pais = 'Perú'; }
  else if (/^57/.test(p))          { offset = -5; pais = 'Colombia'; }
  else if (/^593/.test(p))         { offset = -5; pais = 'Ecuador'; }
  else if (/^507/.test(p))         { offset = -5; pais = 'Panamá'; }
  else if (/^1787|^1939/.test(p))  { offset = -4; pais = 'Puerto Rico'; }
  else if (/^58/.test(p))          { offset = -4; pais = 'Venezuela'; }
  else if (/^56/.test(p))          { offset = -4; pais = 'Chile'; }
  else if (/^54/.test(p))          { offset = -3; pais = 'Argentina'; }
  else if (/^598/.test(p))         { offset = -3; pais = 'Uruguay'; }
  else if (/^34/.test(p))          { offset = 2;  pais = 'España'; }
  const dbTz = tzDeDB(sub);
  if (dbTz) { offset = dbTz.offset; pais = dbTz.etiqueta; }
  const localMs = (sub.next_match_utc_ts + offset * 3600) * 1000;
  const dd = new Date(localMs);
  const hh = dd.getUTCHours();
  const mm = dd.getUTCMinutes();
  const ampm = hh >= 12 ? 'PM' : 'AM';
  const h12 = hh === 0 ? 12 : (hh > 12 ? hh - 12 : hh);
  const mStr = mm === 0 ? '' : ':' + String(mm).padStart(2, '0');
  const horaStr = h12 + mStr + ' ' + ampm + ' (hora ' + pais + ')';
  msgWa = msgWa.replace('{{HORA_PROXIMO}}', horaStr);
  msgTg = msgTg.replace('{{HORA_PROXIMO}}', horaStr);
}

// Para goles CON imagen de sponsor: una sola alerta (foto + caption)
