  waPayload = {
    messaging_product: 'whatsapp', recipient_type: 'individual',
    to: sub.phone, type: 'image',
    image: {
      link: image,
      caption: (waText + (promo ? '\n\n' + promo : '')).slice(0, 1024)
    }
  };
} else {
  waPayload = {
    messaging_product: 'whatsapp', recipient_type: 'individual',
    to: sub.phone, type: 'text', text: { body: waText }
  };
}

return [{ json: {
