function flag(n) { return FLAGS[n] || '⚽'; }
function horaSV(utcMs) {
  const d = new Date(utcMs - 6 * 3600 * 1000);
  const hh = d.getUTCHours(); const mm = d.getUTCMinutes();
  const ampm = hh >= 12 ? 'PM' : 'AM';
  const h12 = hh === 0 ? 12 : (hh > 12 ? hh - 12 : hh);
  return h12 + ':' + String(mm).padStart(2, '0') + ' ' + ampm;
}
function fechaSV(ms) { return new Date(ms - 6 * 3600 * 1000).toISOString().slice(0, 10); }

const g   = $getWorkflowStaticData('global');
const now = Date.now();
const out = [];

// Limpieza: purga estado de partidos de hace más de 48 h
for (const k of Object.keys(g)) {
  if (k.startsWith('ftdone_') && g[k] && g[k].ts && (now - g[k].ts) > 48 * 3600000) {
    delete g['ressent_' + k.slice('ftdone_'.length)];
    delete g[k];
  }
}

// ── 1. ¿Hay un partido recién terminado sin resumen? (desde DB — sobrevive a updates del workflow) ──
const dbRows = $input.all().map(i => i.json).filter(r => r && r.partido_id);
if (dbRows.length) {
  const id = String(dbRows[0].partido_id);
  const d = g['ftdone_' + id] || {};
  out.push({ json: { fixture_id: id, home: d.home, away: d.away, hs: d.hs, as_: d.as_ } });

  // ¿Quedan partidos HOY (fecha SV) con kickoff en el futuro?
  const hoy = fechaSV(now);
  const quedan = PARTIDOS.some(p => {
    const t = new Date(p.utc).getTime();
    return t > now && fechaSV(t) === hoy;
  });
  if (!quedan && !g['dailydue']) g['dailydue'] = { ts: now };
}

// ── 2. Resumen del día (30 min después del último FT del día) ──
if (!out.length && g['dailydue'] && (now - g['dailydue'].ts) >= 30 * 60000) {
  const hoy = fechaSV(now);
  if (!g['dailysent_' + hoy]) {
    g['dailysent_' + hoy] = true;
    delete g['dailydue'];

    // Resultados de hoy desde ftdone_*
    const resultados = [];
    for (const k of Object.keys(g)) {
      if (!k.startsWith('ftdone_')) continue;
      const d = g[k];
      if (!d || !d.ts || fechaSV(d.ts) !== hoy) continue;
      resultados.push(`${flag(d.home)} ${d.home}  ${d.hs} – ${d.as_}  ${d.away} ${flag(d.away)}`);
    }

    // Partidos de mañana desde el calendario
    const manana = [];
    for (const p of PARTIDOS) {
      const t = new Date(p.utc).getTime();
      const fManana = fechaSV(now + 24 * 3600 * 1000);
      if (fechaSV(t) !== fManana) continue;
      manana.push(`🕐 ${horaSV(t)} — ${flag(p.home)} ${p.home} vs ${p.away} ${flag(p.away)} (${p.venue}, ${p.city})`);
    }

    const lines = ['📋 RESUMEN DEL DÍA — MUNDIAL 2026', ''];
    if (resultados.length) {
      lines.push('✅ RESULTADOS DE HOY', '');
      resultados.forEach(r => lines.push(r));
    }
    if (manana.length) {
      lines.push('', '⏰ MAÑANA (hora El Salvador / CDMX)', '');
      manana.forEach(m => lines.push(m));
    }
    lines.push('', '#RODAI Sport');
    const msg = lines.join('\n');
    out.push({ json: {
      daily: true, partido_id: 'dia_' + hoy, tipo: 'resumen_dia',
      detalle: 'resdia_' + hoy, home: '', away: '',
      msg_wa: msg, msg_tg: msg, events_count: 1
    } });
  } else {
    delete g['dailydue'];
  }
}

if (!out.length) return [{ json: { skip: true } }];
return out;

