const lines = ['📋 RESUMEN DEL DÍA — Mundial 2026', ''];
for (const fix of fixtures) {
  const h  = fix.teams.home.name, a = fix.teams.away.name;
  const hs = fix.goals?.home, as_ = fix.goals?.away;
  const st = fix.fixture.status?.short;
  if (['FT','AET','PEN'].includes(st))
    lines.push(`✅ ${h} ${hs}–${as_} ${a}`);
  else if (['1H','2H','HT','ET'].includes(st))
    lines.push(`🔴 ${h} ${hs}–${as_} ${a} (en vivo)`);
  else {
    const d = new Date(fix.fixture.date);
    const cdmxH = ((d.getUTCHours() - 6 + 24) % 24).toString().padStart(2,'0');
    const cdmxM = d.getUTCMinutes().toString().padStart(2,'0');
    lines.push(`⏰ ${h} vs ${a} (${cdmxH}:${cdmxM} hora El Salvador / CDMX)`);
  }
}
lines.push('', '¡Hasta mañana! 🌙');

const msg = lines.join('\n');
return [{ json:{
  events_count:1, partido_id:'daily', tipo:'resumen',
  detalle:`daily_${new Date().toISOString().slice(0,10)}`,
  msg_wa: msg.replace('/stop','STOP'),
  msg_tg: msg
}}];

const sub   = $('Loop Subs DAI').first().json;
const promo = sub.sponsor_promo || '';
const image = sub.sponsor_image || '';

const waFinal = promo ? sub.msg_wa + '\n\n' + promo : sub.msg_wa;
const tgFinal = sub.msg_tg;

const waPayload = {
  messaging_product:'whatsapp', recipient_type:'individual',
  to: sub.phone, type:'text', text:{ body: waFinal }
};
return [{ json:{
  phone: sub.phone, platform: sub.platform,
  telegram_chat_id: sub.telegram_chat_id,
  partido_id: sub.partido_id, tipo: sub.tipo, detalle: sub.detalle,
  msg_tg: tgFinal, sponsor_image: image, sponsor_promo: promo,
  wa_body: JSON.stringify(waPayload)
} }];

const e = $input.first().json;
const tipo = e.tipo || 'evento';
const home = e.home || 'Local';
const away = e.away || 'Visitante';
const hs   = e.hs  !== undefined ? e.hs  : (e.goals?.home  ?? 0);
const as_  = e.as_ !== undefined ? e.as_ : (e.goals?.away  ?? 0);

let promptLines = [`TIPO DE ALERTA: ${tipo.toUpperCase()}`, `Partido: ${home} vs ${away}`, `Marcador: ${home} ${hs} — ${as_} ${away}`];
promptLines.push('CONTENIDO BASE (datos reales — usa estos nombres y minutos EXACTOS, no inventes nada):');
promptLines.push(e.msg_wa || e.msg_tg || '');
promptLines.push('REGLA: conserva SIEMPRE nombres de jugadores y minutos del contenido base. Redacta como cronista de radio breve.');

if (tipo === 'goal') {
  promptLines.push('INSTRUCCION OBLIGATORIA: narra el gol como cronista de radio emocionado. DEBES mencionar el NOMBRE del goleador y del asistente (si hay) y el MINUTO. Describe la jugada para quien NO esta viendo el partido. NO omitas nombres ni minuto JAMAS.');
  if (e.scorer || e.last_scorer)  promptLines.push(`Goleador: ${e.scorer || e.last_scorer || '?'}`);
  if (e.assist || e.last_assist)  promptLines.push(`Asistencia: ${e.assist || e.last_assist}`);
  if (e.detail || e.last_detail)  promptLines.push(`Tipo de gol: ${e.detail || e.last_detail}`);
  if (e.elapsed || e.last_minute) promptLines.push(`Minuto: ${e.elapsed || e.last_minute}'`);
  if (e.narrative)                promptLines.push(`Narrativa: ${e.narrative}`);
  if (e.ctxLabel)                 promptLines.push(`Contexto: ${e.ctxLabel}`);
}
if (tipo === 'halftime') {
  promptLines.push('Evento: FIN PRIMER TIEMPO');
  if (e.goals_ht && e.goals_ht.length) promptLines.push(`Goles 1T: ${e.goals_ht.map(g=>g.player?.name+'('+g.time?.elapsed+"')").join(', ')}`);
}
if (tipo === 'h2_start')  promptLines.push('Evento: INICIO SEGUNDO TIEMPO');
if (tipo === 'fulltime') {
  promptLines.push('Evento: RESULTADO FINAL');
  if (e.mvp_name) promptLines.push(`MVP: ${e.mvp_name}`);
  if (e.winner)   promptLines.push(`Ganador: ${e.winner}`);
}
if (tipo === 'kickoff') {
  if (e.venue)  promptLines.push(`Estadio: ${e.venue}`);
  if (e.league) promptLines.push(`Liga: ${e.league}`);
  promptLines.push('Evento: INICIO DEL PARTIDO');
}
if (tipo === 'prepartido') {
  if (e.venue)  promptLines.push(`Estadio: ${e.venue}`);
  if (e.hhmm)   promptLines.push(`Hora: ${e.hhmm} CDMX`);
  if (e.league) promptLines.push(`Liga: ${e.league}`);
  promptLines.push('Evento: PRÓXIMO PARTIDO (15 min)');
}
if (tipo === 'resumen') {
  promptLines.push('Lista de partidos del día con resultados incluida en narrativa');
}

return [{ json: { ...e, ai_prompt: promptLines.join('\n') } }];

